export type Category = 'everyday' | 'verbs' | 'adjectives' | 'nouns' | 'sentences' | 'technical';

export type Gender = 'masculine' | 'feminine';
export type Binyan = 'Пааль' | 'Пиэль' | 'Хифиль' | 'Нифаль' | 'Пуаль' | 'Хуфаль' | 'Хитпаэль';

export interface WordForms {
  feminine?: string;
  plural?: string;
  femininePlural?: string;
  smikhut?: string;
  smikhutPlural?: string;
}

export interface VerbConjugation {
  past?: string;      // прошедшее
  present?: string;   // настоящее
  future?: string;    // будущее
  imperative?: string; // повелительное
}

export interface Word {
  id: string;
  hebrew: string;
  transcription: string;
  russian: string;
  category: Category;
  subcategory?: string;
  gender?: Gender;
  forms?: WordForms;
  binyan?: Binyan;
  preposition?: string;   // предлог для глагола
  root?: string;          // שורש (корень слова)
  conjugation?: VerbConjugation;
  // Русская транскрипция для всех времен глагола
  conjugationTranscription?: {
    past?: string;
    present?: string;
    future?: string;
    imperative?: string;
  };
  example?: {
    hebrew: string;
    transcription?: string;
    russian: string;
  };
  // Для выражений и предложений (пословный разбор)
  fullAnalysis?: Array<{
    word: string;
    translation: string;
    details: string; // часть речи, время, лицо или падеж
  }>;
}

